SELECT SUM(TS.[DAILY_ARTICLES]) AS WEEKLY_ARTICLES,
	SUM(TS.[DAILY_VIEWS]) AS WEEKLY_VIEWS,
	SUM(TS.[DAILY_SEARCHES]) AS WEEKLY_SEARCHES 
